-- ===========================================================================
-- Benefit Market — Отзывы к видимым (published) льготам BeneFit Studio
-- ===========================================================================
-- Целевые офферы:
--   • «Wellness-программа «Энергия»»            (published)
--   • «Мастер-класс «Деловые коммуникации»»     (published)
--
-- Файл идемпотентен. UNIQUE (user_id, provider_offering_id) защищает от дублей.
-- Использует пользователей, КОТОРЫЕ НЕ ИСПОЛЬЗОВАЛИСЬ в seed_more_data.sql
-- для этих же офферов, плюс новых из 70..7e.
-- ===========================================================================

CREATE EXTENSION IF NOT EXISTS pgcrypto;

DO $more_visible$
DECLARE
  _tenant_id uuid;
  r          record;
  _idx       int := 0;
  _cnt       int := 0;
BEGIN
  SELECT id INTO _tenant_id FROM tenants
   WHERE id != '00000000-0000-0000-0000-000000000000'
   ORDER BY created_at ASC LIMIT 1;

  FOR r IN
    SELECT u.id AS user_id, po.id AS po_id, val.rating, val.title, val.body
    FROM (VALUES
      -- ==================== Wellness-программа «Энергия» (15 отзывов от других юзеров) ====================
      ('00000000-0000-4000-8000-000000000010'::uuid, 'Wellness-программа «Энергия»', 5, 'Топ-льгота для команды',          'Беру для топ-менеджмента и сама прошла. Программа возвращает ресурс — заметно по продуктивности.'),
      ('00000000-0000-4000-8000-000000000020'::uuid, 'Wellness-программа «Энергия»', 5, 'HR ставит как стандарт',           'Раздаём ссылку при онбординге руководителей. После годового аврала — обязательная льгота.'),
      ('00000000-0000-4000-8000-000000000032'::uuid, 'Wellness-программа «Энергия»', 5, 'Аналитик восстановился',           'После сезона релизов — программа спасла от выгорания. Сон вернулся за 3 недели.'),
      ('00000000-0000-4000-8000-000000000042'::uuid, 'Wellness-программа «Энергия»', 4, 'Полезно для поддержки',            'L1 — постоянно стресс. Программа учит снимать его без вреда для тела.'),
      ('00000000-0000-4000-8000-000000000045'::uuid, 'Wellness-программа «Энергия»', 5, 'Фронтенду понравилось',            'Спина после Figma и кода — теперь под контролем. Тренер показал упражнения, делаю каждый день.'),
      ('00000000-0000-4000-8000-000000000046'::uuid, 'Wellness-программа «Энергия»', 5, 'Дизайнеру в кайф',                 'Йога + питание + медитации — пакет правильный. Прокачала отношение к телу.'),
      ('00000000-0000-4000-8000-000000000047'::uuid, 'Wellness-программа «Энергия»', 4, 'Junior берёт впервые',             'Сначала переживал, что не вытяну. Куратор адаптирует под уровень — справился.'),
      ('00000000-0000-4000-8000-000000000048'::uuid, 'Wellness-программа «Энергия»', 5, 'Финансист в форме',                'Цифры в Excel и цифры на весах — теперь обе под контролем. Спасибо нутрициологу.'),
      ('00000000-0000-4000-8000-000000000049'::uuid, 'Wellness-программа «Энергия»', 5, 'Руководителю продаж — must',       'После сезона переговоров — обязательно беру программу. Лучшая инвестиция года.'),
      ('00000000-0000-4000-8000-00000000004a'::uuid, 'Wellness-программа «Энергия»', 5, 'HR-специалист на ресурсе',         'Работаю с людьми весь день — программа помогает не выгорать. Команде советую.'),
      ('00000000-0000-4000-8000-00000000004b'::uuid, 'Wellness-программа «Энергия»', 4, 'Mobile-разработчик стартует',      'Сидячая работа + офис — спина пострадала. Программа дала старт нормальной активности.'),
      ('00000000-0000-4000-8000-00000000004c'::uuid, 'Wellness-программа «Энергия»', 5, 'Контент-менеджер в потоке',        'Удалёнка — самое сложное. Программа структурирует день и тело.'),
      ('00000000-0000-4000-8000-00000000004d'::uuid, 'Wellness-программа «Энергия»', 5, 'BI-аналитик отслеживает прогресс', 'Показатели сна, активности — всё на дашборде. Программа подходит data-people.'),
      ('00000000-0000-4000-8000-00000000004e'::uuid, 'Wellness-программа «Энергия»', 5, 'Финдиректор перезагружается',      'Раз в год — обязательная программа. После закрытия квартала — единственный способ восстановиться.'),
      ('00000000-0000-4000-8000-000000000071'::uuid, 'Wellness-программа «Энергия»', 5, 'DevOps снимает стресс правильно',  'Раньше снимал стресс пивом, теперь — программой. Команда заметила разницу.'),
      ('00000000-0000-4000-8000-000000000072'::uuid, 'Wellness-программа «Энергия»', 4, 'Junior-дизайнер в восторге',       'Перед оффером боялась стресса. Программа помогла встроиться без выгорания.'),
      ('00000000-0000-4000-8000-000000000074'::uuid, 'Wellness-программа «Энергия»', 5, 'Продакт-лиду — обязательно',       'Лидерство = выносливость. Программа возвращает её, когда уже выжата.'),
      ('00000000-0000-4000-8000-000000000075'::uuid, 'Wellness-программа «Энергия»', 5, 'QA после релиза',                  'Лучший отдых после спринта — программа. Команде советую.'),
      ('00000000-0000-4000-8000-000000000076'::uuid, 'Wellness-программа «Энергия»', 5, 'Бизнес-аналитик с энергией',       'После 8 часов созвонов — нужен ресурс. Программа учит его сохранять.'),
      ('00000000-0000-4000-8000-000000000077'::uuid, 'Wellness-программа «Энергия»', 4, 'Поддержка тоже устаёт',            'L1 — мощный стрессогенный поток. Программа учит фильтровать его.'),
      ('00000000-0000-4000-8000-000000000079'::uuid, 'Wellness-программа «Энергия»', 5, 'Тимлид мобилки на ресурсе',        'После релиза мобильного приложения — программа возвращает форму за 2 недели.'),
      ('00000000-0000-4000-8000-00000000007a'::uuid, 'Wellness-программа «Энергия»', 5, 'Финансист в фокусе',               'Программа структурирует день. Финансовая отчётность идёт легче, когда тело в порядке.'),
      ('00000000-0000-4000-8000-00000000007b'::uuid, 'Wellness-программа «Энергия»', 4, 'Java-разработчик стартанул',       'Бэкенд + спина = боль. Программа дала упражнения, теперь утром делаю обязательно.'),
      ('00000000-0000-4000-8000-00000000007c'::uuid, 'Wellness-программа «Энергия»', 5, 'PR в форме',                       'Перед запуском кампании — программа возвращает ресурс. Голос звучит увереннее.'),
      ('00000000-0000-4000-8000-00000000007e'::uuid, 'Wellness-программа «Энергия»', 5, 'Директор разработки в форме',      'Команде показываю на собственном примере. Программа отлично подходит руководителям.'),

      -- ==================== Мастер-класс «Деловые коммуникации» (20 отзывов) ====================
      ('00000000-0000-4000-8000-000000000010'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Прокачал переговоры',            'После мастер-класса переговоры с подрядчиками идут быстрее и без эмоций.'),
      ('00000000-0000-4000-8000-000000000020'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'HR ставит для middle+',           'Прохожу с командой раз в полгода. Конфликты внутри команды решаются проще.'),
      ('00000000-0000-4000-8000-000000000030'::uuid, 'Мастер-класс «Деловые коммуникации»', 4, 'Полезно для разработчиков',       'Раньше письма по работе писал в стиле GitHub-комментариев. После — тон точнее.'),
      ('00000000-0000-4000-8000-000000000031'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Junior подтянул soft skills',     'С design-критики — конструктив, без перехода на личное. Это мастер-класс дал.'),
      ('00000000-0000-4000-8000-000000000032'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Аналитик защищает результаты',    'Презентации стало проще. Цифры — те же, эффект — другой.'),
      ('00000000-0000-4000-8000-000000000033'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Senior на ретро',                 'Ретро команды без обвинений — это мастер-класс научил структурировать обратную связь.'),
      ('00000000-0000-4000-8000-000000000034'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Тимлиду — обязательно',           'Управление через коммуникацию — это всё, что у нас есть. Мастер-класс закрывает базу.'),
      ('00000000-0000-4000-8000-000000000035'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Продуктовому директору тоже',     'На уровне совета директоров — те же навыки. Мастер-класс универсален.'),
      ('00000000-0000-4000-8000-000000000040'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Маркетинг закрыл сложного клиента','Сложный клиент стал лояльным после правильно построенного звонка. Мастер-класс работает.'),
      ('00000000-0000-4000-8000-000000000041'::uuid, 'Мастер-класс «Деловые коммуникации»', 4, 'Бэкенду на код-ревью',            'Тон комментариев на PR изменился. Команда стала спокойнее на ревью.'),
      ('00000000-0000-4000-8000-000000000043'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Аналитику на стейкхолдер-митинге', 'Презентация результатов A/B-теста прошла без сопротивления. Раньше всегда был спор.'),
      ('00000000-0000-4000-8000-000000000044'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Маркетинг-лиду — must',           'Сложные разговоры с подрядчиками — теперь не страшно. Мастер-класс дал инструменты.'),
      ('00000000-0000-4000-8000-000000000048'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Финансы на ревью бюджета',        'Бюджетный комитет — раньше всегда споры. Теперь — обсуждение по существу.'),
      ('00000000-0000-4000-8000-000000000049'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Продажам — основа',               'Возражения клиентов теперь не тормозят сделку. Мастер-класс дал базу для всей команды.'),
      ('00000000-0000-4000-8000-00000000004a'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'HR на интервью',                  'Интервью с кандидатами стали структурнее. Мастер-класс дал чек-лист для сложных вопросов.'),
      ('00000000-0000-4000-8000-00000000004d'::uuid, 'Мастер-класс «Деловые коммуникации»', 4, 'BI на ревью отчётов',              'Стейкхолдеры стали лучше понимать результаты. Презентация теперь — не битва, а диалог.'),
      ('00000000-0000-4000-8000-000000000070'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'SMM на пресс-конференции',         'Журналисты задавали сложные вопросы — отвечала без срывов. Мастер-класс помог.'),
      ('00000000-0000-4000-8000-000000000074'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Продакт-лид на стратегической сессии', 'Сессия с C-level — раньше всегда боялась. Теперь — спокойно и по делу.'),
      ('00000000-0000-4000-8000-000000000078'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'HRBP-инструмент',                  'Работа с командой и руководителями — теперь без посредников. Мастер-класс дал базу.'),
      ('00000000-0000-4000-8000-00000000007e'::uuid, 'Мастер-класс «Деловые коммуникации»', 5, 'Директору на совете',              'Раз в квартал — отчёт перед советом директоров. Мастер-класс изменил формат подачи.')
    ) AS val(user_id, po_name, rating, title, body)
    JOIN users u               ON u.id   = val.user_id
    JOIN provider_offerings po ON po.name = val.po_name
    WHERE u.tenant_id = _tenant_id
  LOOP
    INSERT INTO reviews (provider_offering_id, tenant_id, user_id, rating, title, body, status, created_at, updated_at)
    SELECT r.po_id, _tenant_id, r.user_id, r.rating, r.title, r.body,
           'visible'::review_status,
           NOW() - ((3 + ((_idx * 5) % 100)) || ' days')::interval,
           NOW() - ((3 + ((_idx * 5) % 100)) || ' days')::interval
    WHERE NOT EXISTS (
      SELECT 1 FROM reviews WHERE user_id = r.user_id AND provider_offering_id = r.po_id
    );
    _idx := _idx + 1;
    _cnt := _cnt + 1;
  END LOOP;

  RAISE NOTICE '======================================';
  RAISE NOTICE 'Обработано пар (user, offering): %', _cnt;
  RAISE NOTICE '======================================';

  -- Контрольные суммы по двум видимым офферам
  PERFORM 1;
  FOR r IN
    SELECT po.name, po.status, po.avg_rating, po.review_count
    FROM provider_offerings po
    JOIN providers pr ON pr.id = po.provider_id
    WHERE pr.slug = 'benefit-studio'
      AND po.name IN ('Wellness-программа «Энергия»', 'Мастер-класс «Деловые коммуникации»')
  LOOP
    RAISE NOTICE 'BS oferring: % | status=% | avg=% | count=%',
      r.name, r.status, r.avg_rating, r.review_count;
  END LOOP;
END $more_visible$;
